import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            boolean ok0 = true, ok1 = true;
            for (int i = 0; i < N; i++) {
                char exp0 = (i % 2 == 0) ? '0' : '1';
                char exp1 = (i % 2 == 0) ? '1' : '0';
                char c = S.charAt(i);
                if (c != '?') {
                    if (c != exp0) ok0 = false;
                    if (c != exp1) ok1 = false;
                }
            }
            if (ok0) {
                for (int i = 0; i < N; i++) out.append((i % 2 == 0) ? '0' : '1');
                out.append('\n');
            } else if (ok1) {
                for (int i = 0; i < N; i++) out.append((i % 2 == 0) ? '1' : '0');
                out.append('\n');
            } else {
                for (int i = 0; i < N; i++) {
                    char c = S.charAt(i);
                    out.append(c == '?' ? '0' : c);
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

