#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        S = list(next(it))
        ok0 = True
        ok1 = True
        for i,ch in enumerate(S):
            exp0 = '0' if i%2==0 else '1'
            exp1 = '1' if i%2==0 else '0'
            if ch!='?':
                if ch!=exp0:
                    ok0=False
                if ch!=exp1:
                    ok1=False
        if ok0:
            out_lines.append(''.join('0' if i%2==0 else '1' for i in range(N)))
        elif ok1:
            out_lines.append(''.join('1' if i%2==0 else '0' for i in range(N)))
        else:
            out_lines.append(''.join('0' if ch=='?' else ch for ch in S))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

